export interface Product {
  id: number;
  name: string;
  description: string;
  price: number;
  category_id: number;
  category_name: string;
  brand: string;
  tags: string[];
  in_stock: boolean;
  created_at: Date;
}

import { esClient } from './client';
import { db } from '../db';

const INDEX = 'products';

const MAPPING = {
  mappings: {
    properties: {
      id: { type: 'integer' },
      name: { type: 'text', analyzer: 'english', fields: { keyword: { type: 'keyword' } } },
      description: { type: 'text', analyzer: 'english' },
      brand: { type: 'keyword' },
      category_name: { type: 'keyword' },
      tags: { type: 'keyword' },
      price: { type: 'double' },
      in_stock: { type: 'boolean' },
      created_at: { type: 'date' },
    }
  },
  settings: {
    number_of_shards: 2,
    number_of_replicas: 1,
  }
};

export async function createIndex() {
  const exists = await esClient.indices.exists({ index: INDEX });
  if (!exists) {
    await esClient.indices.create({ index: INDEX, body: MAPPING });
    console.log('Created products index');
  }
}

export async function bulkIndex() {
  const BATCH = 1000;
  let offset = 0;
  let total = 0;
  while (true) {
    const products = await db('products')
      .join('categories', 'products.category_id', 'categories.id')
      .select('products.*', 'categories.name as category_name')
      .limit(BATCH).offset(offset);
    if (products.length === 0) break;
    const ops = products.flatMap(p => [
      { index: { _index: INDEX, _id: p.id } },
      { ...p }
    ]);
    await esClient.bulk({ operations: ops });
    total += products.length;
    offset += BATCH;
    console.log(`Indexed ${total} products...`);
  }
  console.log(`Done. Total: ${total}`);
}

export async function indexProduct(product: any) {
  await esClient.index({ index: INDEX, id: product.id, document: product });
}

export async function deleteProduct(id: number) {
  await esClient.delete({ index: INDEX, id });
}

import { esClient } from './client';

interface SearchParams {
  q: string;
  category?: string;
  brand?: string;
  minPrice?: number;
  maxPrice?: number;
  inStock?: boolean;
  page?: number;
  limit?: number;
}

export async function searchProducts(params: SearchParams) {
  const { q, category, brand, minPrice, maxPrice, inStock, page = 1, limit = 20 } = params;
  const must: any[] = [];
  const filter: any[] = [];

  if (q) {
    must.push({
      multi_match: {
        query: q,
        fields: ['name^3', 'description', 'brand^2', 'tags'],
        type: 'best_fields',
        fuzziness: 'AUTO',
      }
    });
  }

  if (category) filter.push({ term: { category_name: category } });
  if (brand) filter.push({ term: { brand } });
  if (inStock !== undefined) filter.push({ term: { in_stock: inStock } });
  if (minPrice !== undefined || maxPrice !== undefined) {
    filter.push({ range: { price: { gte: minPrice, lte: maxPrice } } });
  }

  const result = await esClient.search({
    index: 'products',
    from: (page - 1) * limit,
    size: limit,
    query: { bool: { must, filter } },
    aggs: {
      categories: { terms: { field: 'category_name', size: 20 } },
      brands: { terms: { field: 'brand', size: 20 } },
      price_stats: { stats: { field: 'price' } },
    }
  });

  return {
    hits: result.hits.hits.map(h => h._source),
    total: (result.hits.total as any).value,
    facets: {
      categories: (result.aggregations?.categories as any)?.buckets,
      brands: (result.aggregations?.brands as any)?.buckets,
      priceRange: result.aggregations?.price_stats,
    }
  };
}
